const crmAction=async(fn:string,params:any)=>{if(!session?.access_token)return null;try{const r=await fetch(SB_URL+'/rest/v1/rpc/'+fn,{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+session.access_token,'apikey':SB_KEY},body:JSON.stringify(params)});return await r.json();}catch(e){console.error(e);return null;}};
const refreshRoleDash=async()=>{if(!crmViewAs||!session?.access_token)return;try{const r=await fetch(SB_URL+'/rest/v1/rpc/crm_role_dashboard',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+session.access_token,'apikey':SB_KEY},body:JSON.stringify({p_role:crmViewAs.role,p_entity_table:crmViewAs.entity_table||null,p_entity_ids:crmViewAs.entity_ids||[]})});setCrmRoleDash(await r.json());}catch(e){console.error(e);}};const canDo=(p:string):boolean=>{if(!crmViewAs)return true;const r=crmViewAs.role;if(!r||r==='owner'||r==='director')return true;const m:any={finance:['hotel_head','restaurant_head','tour_head','education_head','sales_head','hotel_partner','restaurant_partner','tour_partner','masterclass_partner','banya_partner','shop_partner'],bookings:['hotel_head','tour_head','education_head','sales_head','entertainment_head','receptionist','hotel_partner','tour_partner','masterclass_partner','banya_partner','cashier'],reviews:['hotel_head','restaurant_head','tour_head','education_head','marketing_head','hotel_partner','restaurant_partner','tour_partner','masterclass_partner','banya_partner','shop_partner','attraction_partner'],staff:['hotel_head','restaurant_head','tour_head','education_head'],orders:['restaurant_head','sales_head','kitchen','delivery','waiter','concierge','restaurant_partner','shop_partner','cashier'],content:['marketing_head','content_manager'],guests:['hotel_head','restaurant_head','tour_head','education_head','sales_head','receptionist','concierge','hotel_partner','restaurant_partner','tour_partner','masterclass_partner','banya_partner','support']};return!m[p]||m[p].includes(r);};const [crmEditGuest,setCrmEditGuest]=useState(false);const [crmGuestEdit,setCrmGuestEdit]=useState<any>({});const [crmGuestSearch,setCrmGuestSearch]=useState('');const [crmGuestEvts,setCrmGuestEvts]=useState<any[]>([]);const [crmGuest360,setCrmGuest360]=useState<any>(null);const [crmGuestTab,setCrmGuestTab]=useState('overview');const [crmContent,setCrmContent]=useState<any>({hotels:[],restaurants:[],tours:[],masterclasses:[],events:[]});const [crmContentSummary,setCrmContentSummary]=useState<any>(null);const [crmContentTab,setCrmContentTab]=useState<string>('hotels');const [crmContentEdit,setCrmContentEdit]=useState<any>(null);const [crmContentSearch,setCrmContentSearch]=useState('');const [crmContentSaving,setCrmContentSaving]=useState(false);
const contentNameField:any={hotels:'name',restaurants:'name_ru',tours:'name_ru',masterclasses:'name_ru',events:'name_ru'};
const contentActiveField:any={hotels:'active',restaurants:'active',tours:'is_available',masterclasses:'is_available',events:'is_published'};
const saveContentItem=async(table:string,item:any)=>{if(!session?.access_token)return;setCrmContentSaving(true);try{const isNew=!item.id;const url=SB_URL+'/rest/v1/'+table+(isNew?'':('?id=eq.'+item.id));const body={...item};delete body.id;delete body.created_at;body.updated_at=new Date().toISOString();const r=await fetch(url,{method:isNew?'POST':'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+session.access_token,'apikey':SB_KEY,'Prefer':isNew?'return=representation':'return=minimal'},body:JSON.stringify(body)});if(r.ok){const nf=contentNameField[table];const sel=table==='hotels'?'id,name,slug,type,price_from,rating,stars,active,rooms_count,tagline,cover_image_url,amenities,created_at,updated_at':table==='restaurants'?'id,name_ru,cuisine_type,avg_check,rating,active,tagline,cover_image_url,seating_capacity,dietary_tags,created_at,updated_at':table==='tours'?'id,name_ru,type,price,duration_minutes,max_participants,rating,is_available,cover_emoji,created_at,updated_at':table==='masterclasses'?'id,name_ru,category,price,duration_min,max_persons,min_age,is_available,cover_emoji,location_ru,created_at,updated_at':'id,name_ru,type,starts_at,ends_at,price,is_free,is_published,cover_emoji,location_ru,created_at,updated_at';const fresh=await sbAuthGet(session.access_token,table+'?select='+sel+'&order='+(table==='masterclasses'?'sort_order':table==='events'?'starts_at.desc':nf)+'.asc');setCrmContent((p:any)=>({...p,[table]:fresh||p[table]}));setCrmContentEdit(null);sbAuthGet(session.access_token,'rpc/crm_content_summary').then((d:any)=>setCrmContentSummary(Array.isArray(d)?d[0]:d||null));}}catch(e){console.error(e);}setCrmContentSaving(false);};
const deleteContentItem=async(table:string,id:string)=>{if(!session?.access_token)return;try{await fetch(SB_URL+'/rest/v1/'+table+'?id=eq.'+id,{method:'DELETE',headers:{'Authorization':'Bearer '+session.access_token,'apikey':SB_KEY}});setCrmContent((p:any)=>({...p,[table]:(p[table]||[]).filter((x:any)=>x.id!==id)}));setCrmContentEdit(null);sbAuthGet(session.access_token,'rpc/crm_content_summary').then((d:any)=>setCrmContentSummary(Array.isArray(d)?d[0]:d||null));}catch(e){console.error(e);}};
const toggleContentActive=async(table:string,id:string,current:boolean)=>{if(!session?.access_token)return;const af=contentActiveField[table];try{await fetch(SB_URL+'/rest/v1/'+table+'?id=eq.'+id,{method:'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+session.access_token,'apikey':SB_KEY,'Prefer':'return=minimal'},body:JSON.stringify({[af]:!current,updated_at:new Date().toISOString()})});setCrmContent((p:any)=>({...p,[table]:(p[table]||[]).map((x:any)=>x.id===id?{...x,[af]:!current}:x)}));}catch(e){console.error(e);}};
const updateBookingStatus=async(bid:string,newStatus:string)=>{if(!session?.access_token||crmUpdating)return;setCrmUpdating(true);try{const r=await fetch(SB_URL+'/rest/v1/bookings?id=eq.'+bid,{method:'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+session.access_token,'apikey':SB_KEY,'Prefer':'return=minimal'},body:JSON.stringify({status:newStatus,updated_at:new Date().toISOString()})});if(r.ok){setCrmData((prev:any)=>({...prev,bookings:(prev.bookings||[]).map((b:any)=>b.id===bid?{...b,status:newStatus}:b)}));setCrmExpanded(null);}}catch(e){console.error(e);}setCrmUpdating(false);};
const crmGlobalSearch=async(q:string)=>{setCrmSearch(q);if(!q.trim()||!session?.access_token){setCrmSearchResults([]);return;}setCrmSearching(true);try{const r=await fetch(SB_URL+'/rest/v1/rpc/crm_global_search',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+session.access_token,'apikey':SB_KEY},body:JSON.stringify({p_query:q.trim()})});if(r.ok){const data=await r.json();const flat:any[]=[];['bookings','orders','reviews','guests','leads','staff','tasks'].forEach(k=>{(data[k]||[]).forEach((item:any)=>flat.push(item));});setCrmSearchResults(flat);}}catch(e){}setCrmSearching(false);};
const toggleTask=async(taskId:string,current:string)=>{if(!session?.access_token)return;const ns=current==='done'?'todo':'done';try{await fetch(SB_URL+'/rest/v1/crm_tasks?id=eq.'+taskId,{method:'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+session.access_token,'apikey':SB_KEY,'Prefer':'return=minimal'},body:JSON.stringify({status:ns,completed_at:ns==='done'?new Date().toISOString():null})});setCrmTasks(prev=>prev.map(t=>t.id===taskId?{...t,status:ns}:t));}catch(e){console.error(e);}};
const submitBooking=async()=>{if(!session?.access_token||!crmBF.name||!crmBF.hotel||!crmBF.from||!crmBF.to)return;setCrmUpdating(true);try{const r=await fetch(SB_URL+'/rest/v1/rpc/crm_create_booking',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+session.access_token,'apikey':SB_KEY},body:JSON.stringify({p_guest_name:crmBF.name,p_guest_phone:crmBF.phone||null,p_hotel_name:crmBF.hotel,p_date_from:crmBF.from,p_date_to:crmBF.to,p_guests_count:crmBF.guests,p_total_price:crmBF.price,p_notes:crmBF.notes||null})});if(r.ok){const newId=await r.json();setCrmData((p:any)=>({...p,bookings:[{id:newId,guest_name:crmBF.name,guest_phone:crmBF.phone||null,hotel_name:crmBF.hotel,item_name:crmBF.hotel,type:'hotel',status:'confirmed',date_from:crmBF.from,date_to:crmBF.to,nights:crmBF.from&&crmBF.to?Math.max(1,Math.round((new Date(crmBF.to).getTime()-new Date(crmBF.from).getTime())/86400000)):null,guests_count:crmBF.guests,total_price:crmBF.price,created_at:new Date().toISOString()},...(p.bookings||[])]}));setCrmBookForm(false);setCrmBF({name:'',phone:'',hotel:'',from:'',to:'',guests:2,price:0,notes:''});setCrmBookSub('list');}}catch(e){console.error(e);}setCrmUpdating(false);};
const saveGuestEdit=async()=>{if(!session?.access_token||!crmGuest)return;setCrmUpdating(true);try{await fetch(SB_URL+'/rest/v1/rpc/crm_update_guest',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+session.access_token,'apikey':SB_KEY},body:JSON.stringify({p_guest_id:crmGuest.id,p_display_name:crmGuestEdit.display_name||null,p_phone:crmGuestEdit.phone||null,p_email:crmGuestEdit.email||null,p_vip:crmGuestEdit.vip_status??null})});const updated={...crmGuest,...crmGuestEdit};setCrmGuest(updated);setCrmData((p:any)=>({...p,guests:(p.guests||[]).map((g:any)=>g.id===crmGuest.id?updated:g)}));setCrmEditGuest(false);}catch(e){console.error(e);}setCrmUpdating(false);};
const openGuestProfile=async(guest:any)=>{setCrmGuest(guest);setCrmNoteEdit(guest.notes||'');setCrmEditGuest(false);setCrmGuestEdit({});setCrmGuestEvts([]);setCrmGuest360(null);setCrmGuestTab('overview');if(session?.access_token&&guest?.id){try{const r=await fetch(SB_URL+'/rest/v1/crm_guest_events?select=event_type,title,description,amount,created_at&guest_id=eq.'+guest.id+'&order=created_at.desc&limit=20',{headers:{'Authorization':'Bearer '+session.access_token,'apikey':SB_KEY}});if(r.ok){const data=await r.json();setCrmGuestEvts(data||[]);}}catch(e){console.error(e);}try{const r2=await fetch(SB_URL+'/rest/v1/rpc/crm_guest_profile_360',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+session.access_token,'apikey':SB_KEY},body:JSON.stringify({p_guest_id:guest.id})});if(r2.ok){const d360=await r2.json();setCrmGuest360(d360);}}catch(e2){console.error(e2);}}};
const respondToReview=async(rid:string,response:string)=>{if(!session?.access_token||crmUpdating||!response.trim())return;setCrmUpdating(true);try{const r=await fetch(SB_URL+'/rest/v1/reviews?id=eq.'+rid,{method:'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+session.access_token,'apikey':SB_KEY,'Prefer':'return=minimal'},body:JSON.stringify({manager_response:response.trim(),response_at:new Date().toISOString()})});if(r.ok){setCrmData((prev:any)=>({...prev,reviews:(prev.reviews||[]).map((rv:any)=>rv.id===rid?{...rv,manager_response:response.trim(),response_at:new Date().toISOString()}:rv)}));setCrmReply('');setCrmExpanded(null);}}catch(e){console.error(e);}setCrmUpdating(false);};
