      sbAuthGet(t,'profiles?select=id,name,phone,email,points,citizenship_level,passport_number,role,referral_code,total_visits,wallet_balance,cashback_percent,photo_url,bio,locale,birth_date,gender,passport_issued_at,passport_expires_at,passport_authority,nationality&id=eq.'+uid).then(p=>{if(p?.[0])setProfile(p[0]);});
      sbAuthGet(t,'user_settings?select=user_id,push_enabled,marketing_consent,theme,locale,face_id_enabled&user_id=eq.'+uid).then(us=>{if(us?.[0])setUserSet(us[0]);});
      sbAuthGet(t,'bookings?select=id,item_name,hotel_name,type,status,total_price,date_from,date_to,guests_count,created_at&user_id=eq.'+uid+'&order=created_at.desc&limit=30').then(d=>setBookingItems(d||[]));
      sbAuthGet(t,'orders?select=id,order_number,type,status,total,guest_name,items,visit_date,created_at&user_id=eq.'+uid+'&order=created_at.desc&limit=30').then(d=>setUserOrders(d||[]));
      sbAuthGet(t,'receipts?select=id,receipt_code,category,total,status,created_at,points_earned,countries_unlocked,receipt_items(item_name,item_type,emoji,line_total,country_visited,details)&order=created_at.desc&limit=50').then(d=>setMyOrders(d||[]));
      sbAuthGet(t,'favorites?select=id,item_id,item_name,item_emoji,item_type,created_at&user_id=eq.'+uid+'&order=created_at.desc').then(d=>setFavs(d||[]));
      sb('contact_requests','select=*&order=created_at.desc&limit=20').then(d=>setMyRequests(_safe(d||[])));
