                <div style={{fontSize:28,fontWeight:800,color:'#fff',fontFamily:FD}}>{revs.length>0?(revs.reduce((s:number,r:any)=>s+(r.rating||0),0)/revs.length).toFixed(1):'—'} ⭐</div>
