{urg&&<div style={{padding:'2px 8px',borderRadius:8,background:urg.c+'14',fontSize:10,fontWeight:700,color:urg.c,fontFamily:FT,flexShrink:0,whiteSpace:'nowrap',animation:urg.pulse?'crmPulse 2s infinite':''}}>{urg.l}</div>}
