<div style={{width:50,height:3,borderRadius:2,background:'rgba(118,118,128,.06)',marginTop:4,marginLeft:'auto',overflow:'hidden'}}><div style={{height:'100%',borderRadius:2,background:pricePct>80?'#34C759':pricePct>40?'#007AFF':'rgba(60,60,67,.2)',width:pricePct+'%',transition:'width .4s'}}/></div>
