{typeof b.room_cleaned==='boolean'&&<div style={{padding:'10px 12px',borderRadius:14,background:b.room_cleaned?'rgba(52,199,89,.05)':'rgba(255,59,48,.05)'}}><div style={{fontSize:11,color:'rgba(60,60,67,.4)',fontFamily:FT,marginBottom:2}}>{'Уборка'}</div><div style={{fontSize:14,fontWeight:600,color:b.room_cleaned?'#34C759':'#FF3B30',fontFamily:FT}}>{b.room_cleaned?'Убрано':'Не убрано'}</div></div>}
