<div className="tap" onClick={()=>{try{navigator.clipboard.writeText(b.guest_phone);navigator?.vibrate?.(3);}catch(_){}}} style={{flex:1,height:40,borderRadius:14,background:'rgba(0,122,255,.06)',border:'0.5px solid rgba(0,122,255,.1)',display:'flex',alignItems:'center',justifyContent:'center',gap:6}}><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="#007AFF" strokeWidth="2" strokeLinecap="round"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1"/></svg><span style={{fontSize:13,fontWeight:600,color:'#007AFF',fontFamily:FT}}>{'Копировать'}</span></div>
