<div style={{padding:'2px 8px',borderRadius:8,background:(sc[o.status]||'#8E8E93')+'14',fontSize:10,fontWeight:700,color:sc[o.status]||'#8E8E93',fontFamily:FT,flexShrink:0}}>{sl[o.status]||o.status}</div>
