{/* NPS Card */}
<div style={{borderRadius:20,background:'rgba(255,255,255,.52)',backdropFilter:'blur(40px) saturate(180%)',WebkitBackdropFilter:'blur(40px) saturate(180%)',border:'0.5px solid rgba(255,255,255,.6)',boxShadow:'0 0.5px 0 rgba(255,255,255,.9) inset, 0 2px 12px rgba(0,0,0,.04)',padding:'18px 18px 14px',marginBottom:16}}>
<div style={{fontSize:15,fontWeight:600,color:'rgba(60,60,67,.6)',fontFamily:FT,marginBottom:14}}>NPS — {'индекс лояльности'}</div>
<div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:12}}>
<div style={{textAlign:'center'}}><div style={{fontSize:22,fontWeight:700,color:'var(--label)',fontFamily:FD}}>{(crmData.reviews||[]).length}</div><div style={{fontSize:12,color:'rgba(60,60,67,.6)',fontFamily:FT,marginTop:3}}>{'Всего'}</div></div>
<div style={{textAlign:'center'}}><div style={{fontSize:22,fontWeight:700,color:'#34C759',fontFamily:FD}}>{(crmData.reviews||[]).filter((r:any)=>r.rating>=4).length}</div><div style={{fontSize:12,color:'rgba(60,60,67,.6)',fontFamily:FT,marginTop:3}}>{'Промоутеры'}</div></div>
<div style={{textAlign:'center'}}><div style={{fontSize:22,fontWeight:700,color:'#FF9500',fontFamily:FD}}>{(crmData.reviews||[]).filter((r:any)=>r.rating===3).length}</div><div style={{fontSize:12,color:'rgba(60,60,67,.6)',fontFamily:FT,marginTop:3}}>{'Нейтральные'}</div></div>
<div style={{textAlign:'center'}}><div style={{fontSize:22,fontWeight:700,color:'#FF3B30',fontFamily:FD}}>{(crmData.reviews||[]).filter((r:any)=>r.rating<=2).length}</div><div style={{fontSize:12,color:'rgba(60,60,67,.6)',fontFamily:FT,marginTop:3}}>{'Критики'}</div></div>
</div>
<div style={{marginTop:14}}><div style={{display:'flex',justifyContent:'space-between',marginBottom:6}}><span style={{fontSize:13,color:'rgba(60,60,67,.6)',fontFamily:FT}}>NPS</span><span style={{fontSize:15,fontWeight:700,color:(()=>{const rv=crmData.reviews||[];const p=rv.filter((r:any)=>r.rating>=4).length;const d2=rv.filter((r:any)=>r.rating<=2).length;const n=Math.round((p-d2)/(rv.length||1)*100);return n>50?'#34C759':n>0?'#FF9500':'#FF3B30';})(),fontFamily:FD}}>{(()=>{const rv=crmData.reviews||[];const p=rv.filter((r:any)=>r.rating>=4).length;const d2=rv.filter((r:any)=>r.rating<=2).length;return Math.round((p-d2)/(rv.length||1)*100);})()}</span></div>
<div style={{height:8,borderRadius:4,background:'rgba(118,118,128,.06)',overflow:'hidden'}}><div style={{height:'100%',borderRadius:4,background:'#34C759',width:Math.max(0,Math.min(100,(()=>{const rv=crmData.reviews||[];const p=rv.filter((r:any)=>r.rating>=4).length;const d2=rv.filter((r:any)=>r.rating<=2).length;return(p-d2)/(rv.length||1)*100;})()))+'%',transition:'width .5s cubic-bezier(0.2,0.8,0.2,1)'}}/></div></div>
</div>

