<div className='tap' onClick={async(e:any)=>{e.stopPropagation();if(!session?.access_token||!true)return;await fetch(SB_URL+'/rest/v1/crm_leads?id=eq.'+l.id,{method:'DELETE',headers:{'Authorization':'Bearer '+session.access_token,'apikey':SB_KEY}});setCrmData((p:any)=>({...p,leads:(p.leads||[]).filter((x:any)=>x.id!==l.id)}));}} style={{padding:'6px 12px',borderRadius:14,background:'rgba(255,59,48,.08)',fontSize:12,fontWeight:600,color:'#FF3B30',fontFamily:FT}}>Удалить</div>
