<div style={{width:44,height:44,borderRadius:22,background:g.vip_status?'linear-gradient(135deg,#FFD700,#FFA500)':'rgba(118,118,128,.08)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:17,fontWeight:700,color:g.vip_status?'#7B1818':'rgba(60,60,67,.6)',fontFamily:FT,flexShrink:0}}>{(g.display_name||'G')[0]}</div>
