{labels.map((lb,i)=>{const x=10+i/(days-1)*gw;return <text key={i} x={x} y={h-1} textAnchor="middle" fontSize="9" fill="rgba(60,60,67,.35)" fontFamily="-apple-system,system-ui">{lb}</text>;})}
