<div style={{textAlign:'center',padding:'14px 8px',borderRadius:20,background:'rgba(255,255,255,.52)',backdropFilter:'blur(40px) saturate(180%)',WebkitBackdropFilter:'blur(40px) saturate(180%)',border:'0.5px solid rgba(255,255,255,.6)',boxShadow:'0 0.5px 0 rgba(255,255,255,.9) inset, 0 2px 8px rgba(0,0,0,.03)'}}><div style={{fontSize:17,fontWeight:400,color:'var(--label)',fontFamily:FT}}>{_s(crmGuest.source||'—')}</div><div style={{fontSize:12,color:'rgba(60,60,67,.6)',fontFamily:FT,marginTop:3}}>{'Источник'}</div></div>
