{[{k:'overview',l:'Обзор'},{k:'bookings',l:'Брони'},{k:'calendar',l:'Календарь',n:0},{k:'orders',l:'Заказы'},{k:'reviews',l:'Отзывы'},{k:'points',l:'Баллы'}].map(t=><div key={t.k} className='tap' onClick={()=>setCrmGuestTab(t.k)} style={{padding:'6px 14px',borderRadius:20,fontSize:13,fontWeight:crmGuestTab===t.k?600:500,fontFamily:FT,flexShrink:0,background:crmGuestTab===t.k?'#007AFF':'rgba(120,120,128,.06)',color:crmGuestTab===t.k?'#fff':'rgba(60,60,67,.6)',transition:'box-shadow .2s ease,opacity .12s ease'}}>{t.l}{crmGuest360?.stats?({overview:'',bookings:' '+(crmGuest360.stats.total_bookings||0),orders:' '+(crmGuest360.stats.total_orders||0),reviews:' '+(crmGuest360.stats.total_reviews||0),points:' '+(crmGuest360?.points?.length||0)} as any)[t.k]:''}</div>)}
