          {[0,2,4].map(d=><div key={"hr"+d} style={{position:"absolute",right:52,top:"50%",marginTop:-12,width:24,height:24,borderRadius:12,border:"1px solid rgba(212,175,55,.3)",animation:`hbRing 4s ease-out ${d}s infinite`}}/>)}
          {/* L8: floating cultural particles */}
          {[{x:12,y:18,s:5,d:16,c:"rgba(212,175,55,.6)",a:"hbFloat1"},{x:72,y:68,s:4,d:20,c:"rgba(255,200,150,.5)",a:"hbFloat2"},{x:38,y:82,s:3.5,d:14,c:"rgba(255,255,255,.4)",a:"hbFloat3"},{x:85,y:28,s:4.5,d:18,c:"rgba(212,175,55,.55)",a:"hbFloat1"},{x:22,y:58,s:3,d:22,c:"rgba(255,160,100,.45)",a:"hbFloat2"},{x:58,y:12,s:3.5,d:17,c:"rgba(255,255,255,.35)",a:"hbFloat3"},{x:48,y:48,s:3,d:21,c:"rgba(212,175,55,.45)",a:"hbFloat1"}].map((p,i)=><div key={"fp"+i} style={{position:"absolute",left:p.x+"%",top:p.y+"%",width:p.s,height:p.s,borderRadius:p.s/2,background:p.c,boxShadow:`0 0 ${p.s+2}px ${p.c}`,animation:`${p.a} ${p.d}s ease-in-out ${i*1.5}s infinite`}}/>)}
          {/* L9: top-right inner glow */}
          <div style={{position:"absolute",right:0,top:0,width:"50%",height:"50%",background:"radial-gradient(circle at 100% 0%,rgba(212,175,55,.12),transparent 65%)"}}/>
