{[{p:'Участок',v:'от 500 м\u00b2'},{p:'Стоимость',v:'15\u201380M ₽'},{p:'Срок',v:'8—18 мес.'},{p:'Окупаемость',v:'5—7 лет'},{p:'Доходность',v:'15—25%/год'},{p:'Владение',v:'Собственность'}].map((r:any,i:number)=><div key={i} style={{display:'flex',justifyContent:'space-between',padding:'12px 14px',borderTop:i>0?'1px solid rgba(60,60,67,.06)':'none',background:i%2===0?'#F9FAFB':'#fff'}}><span style={{fontSize:13,fontFamily:FT,color:L2}}>{r.p}</span><span style={{fontSize:13,fontWeight:700,color:P,fontFamily:FD}}>{r.v}</span></div>)}
