<div style={{marginBottom:16}}><div style={{display:'flex',justifyContent:'space-between',marginBottom:6}}><span style={{fontSize:12,color:L2,fontFamily:FT}}>{'1 000 ₽'}</span><span style={{fontSize:12,color:L2,fontFamily:FT}}>{'100 000 ₽'}</span></div><input type="range" min="1000" max="100000" step="500" value={custom} onChange={(e:any)=>{setCustom(Number(e.target.value));setAmt(-1);}} style={{width:'100%',accentColor:GOLD}}/></div>
