<div style={{...GL,borderRadius:14,padding:'12px 14px',marginBottom:16,display:'flex',gap:10,alignItems:'center'}}><div style={{fontSize:18}}>{'\ud83d\udc9b'}</div><div style={{flex:1}}><div style={{fontSize:14,fontWeight:600,fontFamily:FD}}>{'Пожертвование фонду'}</div><div style={{fontSize:11,color:L2,fontFamily:FT}}>{'\u00abДиалог Культур — Единый Мир\u00bb'}</div></div><div style={{fontSize:14,fontWeight:700,color:GOLD,fontFamily:FD,whiteSpace:'nowrap'}}>{custom.toLocaleString('ru-RU')+' ₽'}</div></div>
