  const [showSplash,setShowSplash]=useState(true);const [splashFade,setSplashFade]=useState(false);const [showOnboarding,setShowOnboarding]=useState(()=>{try{if(typeof window!=='undefined'&&window.location.search.includes('onboarding=1'))return true;return !localStorage.getItem('em_onboarded');}catch{return false;}});const [obStep,setObStep]=useState(0);const [showParkMap,setShowParkMap]=useState(false);const [showCalendar,setShowCalendar]=useState(false);const [isOffline,setIsOffline]=useState(false);const [showQRScanner,setShowQRScanner]=useState(false);const [qrStream,setQrStream]=useState<any>(null);const qrVideoRef=React.useRef<any>(null);const qrCanvasRef=React.useRef<any>(null);const [a2hsPrompt,setA2hsPrompt]=useState<any>(null);const [iosConfirm,setIosConfirm]=useState<{title:string,msg:string,action:()=>void,destructive?:boolean}|null>(null);const [iosAlert,setIosAlert]=useState<{title:string,msg:string}|null>(null);const [showA2hs,setShowA2hs]=useState(false);const shareApp=async()=>{try{if(navigator.share){await navigator.share({title:'Этномир',text:'Крупнейший развлекательно-познавательный парк РФ',url:window.location.href});}else{await navigator.clipboard.writeText(window.location.href);}}catch(_){}};
