{Array.from({length:10}).map((_,i)=>{const frac=i/10;const y=frac*140+10;const x1=80+Math.sin(frac*Math.PI*3)*50;const x2=80+Math.sin(frac*Math.PI*3+Math.PI)*50;const s=3+Math.cos(frac*Math.PI*3);const colors=['rgba(180,100,255,.35)','rgba(255,100,180,.3)','rgba(255,160,100,.3)','rgba(255,220,80,.3)','rgba(140,230,140,.3)'];return <React.Fragment key={i}><div style={{position:'absolute',left:x1,top:y,width:s*2,height:s*2,borderRadius:s,background:colors[i%5],animation:`obGlow ${5+i*.3}s ease-in-out ${i*.2}s infinite`}}/><div style={{position:'absolute',left:x2,top:y,width:s*2,height:s*2,borderRadius:s,background:colors[(i+2)%5],animation:`obGlow ${5.5+i*.3}s ease-in-out ${i*.25}s infinite`}}/></React.Fragment>})}
